#include <stdlib.h>
struct Node {
    int data;
    struct Node *next;
};
struct Node* reverse(struct Node *head) {
    struct Node *prev = NULL;
    struct Node *current = head;
    while (current != NULL) {
        current->next = prev;
        prev = current;
        current = current->next;
    }
    return prev;
}

